mapper.insert:
/* osstCallMapper.insertRequestOsstHist */
INSERT INTO MCP_REQUEST_OSST@DL_MCP (
    MVNO_ORD_NO
    , SEQ
    , OSST_ORD_NO
    , PRGR_STAT_CD
    , RSLT_CD
    , RSLT_DT
    , TLPH_NO_STAT_CD
    , ASGN_AGNC_ID
    , TLPH_NO_OWN_CMPN_CD
    , OPEN_SVC_IND_CD
    , ENCD_TLPH_NO
    , TLPH_NO
    , IF_TYPE
    , REGST_DTTM
) VALUES (
    LPAD(#{resNo, jdbcType=VARCHAR}, 14, '0')
    , (SELECT MAX(SEQ) + 1 FROM MCP_REQUEST_OSST@DL_MCP WHERE MVNO_ORD_NO = LPAD(#{resNo, jdbcType=VARCHAR}, 14, '0'))
    , (SELECT MAX(OSST_ORD_NO) FROM MCP_REQUEST_OSST@DL_MCP WHERE MVNO_ORD_NO = LPAD(#{resNo, jdbcType=VARCHAR}, 14, '0') AND PRGR_STAT_CD = 'PC2' AND RSLT_CD = '0000')
    , #{appEventCd, jdbcType=VARCHAR}
    , '0000'
    , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS')
    , #{tlphNoStatCd, jdbcType=VARCHAR}
    , #{asgnAgncId, jdbcType=VARCHAR}
    , #{tlphNoOwnCmncCmpnCd, jdbcType=VARCHAR}
    , #{openSvcIndCd, jdbcType=VARCHAR}
    , #{encdTlphNo, jdbcType=VARCHAR}
    , #{tlphNo, jdbcType=VARCHAR}
    , NVL(#{gubun}, 'WEB')
    , SYSDATE
)

mapper.select:
/* osstCallMapper.getTcpResult */ SELECT RSLT_CD AS rsltCd , RSLT_MSG AS rsltMsg , PRDC_CHK_NOTI_MSG AS prdcChkNotiMsg , NP_NCHRG_AMT AS npNchrgAmt , NP_PNLT_AMT AS npPnltAmt , NP_UNPAY_AMT AS npUnpayAmt , NP_HNDST_INST_AMT AS npHndstInstAmt FROM MCP_REQUEST_OSST@DL_MCP A WHERE MVNO_ORD_NO = LPAD(#{resNo}, 14, '0') AND SEQ = (SELECT MAX(SEQ) FROM MCP_REQUEST_OSST@DL_MCP WHERE MVNO_ORD_NO = A.MVNO_ORD_NO
AND PRGR_STAT_CD = #{appEventCd}
)

mapper.insert:

		SELECT 'AD' || TO_CHAR(SYSDATE,'YYYYMMDD') || TRIM(TO_CHAR(SQ_DIS_AD.NEXTVAL, '000000')) AS apdSeq
		FROM   DUAL

		/* osstCallMapper.insertDisApd */
		INSERT INTO MSP_DIS_APD (
			     APD_SEQ
			    ,REGST_DT
			    ,PROC_YN
			    ,REQUEST_KEY
			    ,RES_NO
			    ,PRMT_ID
			    ,CHNL_CD
			    ,EVNT_CD
			    ,ENGG_MNTH_CNT
			    ,OPEN_AGNT_CD
			    ,RATE_CD
			    ,ON_OFF_TYPE
			    ,OPER_TYPE
			    ,REQ_BUY_TYPE
			    ,REGST_ID
			    ,REGST_DTTM
			    ,PRMT_AGNT_CD
			) VALUES (
			     #{apdSeq}
    			, TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS')
    			, 'N'
    			, #{requestKey}
    			, #{resNo}
    			, #{disPrmtId}
    			, '02'
    			, #{evntCd}
    			, #{agrmTrm}
    			, #{cntpntShopId}
    			, #{socCode}
    			, #{onOffType}
    			, #{operType}
    			, #{reqBuyType}
    			, 'MSP'
    			, SYSDATE
    			, #{cntpntShopId}
			)

mapper.select:
/* osstCallMapper.knoteScanInfoChk */
SELECT  COUNT(1)
FROM    KIS_KNOTE_SCAN_INFO
WHERE   ITEM_ID = #{frmpapId}

/* osstCallMapper.getKnoteOrgn */
SELECT 	CASE
		    WHEN (SELECT TYPE_CD FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = #{cntpntCd} AND ROWNUM = 1) = '30' THEN HGHR_ORGN_CD
		    ELSE ORGN_ID
	    END AS ORGN_ID
FROM 	ORG_ORGN_INFO_MST
WHERE	KT_ORG_ID = #{mngmAgncId}
  AND 	ORGN_ID = #{cntpntCd}

/* osstCallMapper.getKnoteCode */
SELECT  CD_VAL
    	,CD_DSC
		,ETC1
FROM    CMN_GRP_CD_MST
WHERE   GRP_ID = #{grpId}

	AND     CD_VAL = #{cdVal}


	AND     ETC2 = #{ETC2}

AND     USG_YN = 'Y'
